CREATE TABLE wodzone.wod_details (
  id_wod_detail INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  first_name varchar,
  last_name varchar,
  email varchar,
  birth_date timestamp,
  telephone varchar,
  password varchar,
  id_role int,
  tee_shirt int,
  short int,
  pointure int,
  created_at timestamp,
  updated_at timestamp
);

CREATE TABLE wodzone.tailles (
  "id_taille" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "value" varchar(10)
);

CREATE TABLE wodzone.history_team_changes (
  "id_history_team_change" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "id_participant" int,
  "id_user_remplacant" int,
  "id_user_remplace" int,
  "created_at" timestamp
);



