--REQUETE pour PUCES => pour extraire la liste des participant avec un id_competition
SELECT
  sub.id_participant, sub.name, sub.id_division, sub.team AS category, sub.planning_date,
  sub.heat_title, sub.heat_debut, sub.line_number, sub.id_wod, sub.min_id_wod_score_details,
  MAX(CASE WHEN sub.rn = 1 THEN sub.first_name || ' ' || sub.last_name END) AS athlete_1,
  MAX(CASE WHEN sub.rn = 2 THEN sub.first_name || ' ' || sub.last_name END) AS athlete_2,
  MAX(CASE WHEN sub.rn = 3 THEN sub.first_name || ' ' || sub.last_name END) AS athlete_3,
  MAX(CASE WHEN sub.rn = 4 THEN sub.first_name || ' ' || sub.last_name END) AS athlete_4
FROM (
  SELECT
    p.id_participant, d.name, d.id_division, team, line_number, planning_date, heat_title,
    heat_debut, INITCAP(a.first_name) AS first_name, UPPER(a.last_name)    AS last_name,
    DENSE_RANK() OVER (PARTITION BY p.id_participant, w.id_wod ORDER BY a.first_name, a.last_name) AS rn,
    w.id_wod,
    MIN(wsd.id_wod_score_details) OVER (PARTITION BY p.id_participant, w.id_wod) AS min_id_wod_score_details
  FROM wodzone.participants p
  JOIN wodzone.athletes            a   ON a.id_participant   = p.id_participant
  JOIN wodzone.participant_divisions pd ON pd.id_participant = p.id_participant
  JOIN wodzone.divisions           d   ON d.id_division      = pd.id_division
  JOIN wodzone.wods                w   ON w.id_division      = d.id_division
  JOIN wodzone.wod_score_details   wsd ON wsd.id_wod         = w.id_wod
  JOIN wodzone.lines               l   ON l.id_participant   = p.id_participant
  JOIN wodzone.heats               h   ON h.id_heat          = l.id_heat
  JOIN wodzone.planning_wods       pw  ON pw.id_planning_wod = h.id_planning_wod
  JOIN wodzone.competitions        c   ON d.id_competition   = c.id_competition
  WHERE c.id_competition = 96 AND is_for_test_mode = false
) sub
GROUP BY
  sub.id_participant, sub.id_division, sub.name, sub.team, sub.planning_date, sub.line_number, sub.heat_title, 
  sub.heat_debut, sub.id_wod, sub.min_id_wod_score_details
ORDER BY sub.name, sub.heat_debut, sub.line_number;



SELECT 
    d.id_division, 
    d.name,
    w.id_wod,
    MIN(wsd.id_wod_score_details) AS min_id_wod_score_details
FROM wodzone.divisions d
JOIN wodzone.wods w ON w.id_division = d.id_division 
JOIN wodzone.wod_score_details wsd ON wsd.id_wod = w.id_wod 
WHERE d.id_competition = 75
GROUP BY d.id_division, d.name, w.id_wod
order by d.name;

