CREATE OR REPLACE PROCEDURE wodzone.delete_competition(idCompetition integer)
LANGUAGE plpgsql
AS $$
DECLARE 
    divisions_ids INTEGER[];
    wods_ids INTEGER[];
    wod_id INTEGER;
    participants_ids INTEGER[];
    participant_id INTEGER;
begin
	SELECT ARRAY(
		SELECT id_wod FROM wodzone.competitions c
		join wodzone.divisions d on c.id_competition = d.id_competition 
		join wodzone.wods w on d.id_division = w.id_division
		WHERE c.id_competition = idCompetition
	) INTO wods_ids;
    -- Loop through the array and call delete_competition function for each ID
    FOREACH wod_id IN ARRAY wods_ids
    LOOP
        CALL wodzone.delete_wod(wod_id);
    END LOOP;
   SELECT ARRAY(
		SELECT id_participant FROM wodzone.competitions c
		join wodzone.divisions d on c.id_competition = d.id_competition 
		join wodzone.participants p on p.id_division = d.id_division
		WHERE c.id_competition = idCompetition
	) INTO participants_ids;
    -- Loop through the array and call delete_competition function for each ID
    FOREACH participant_id IN ARRAY participants_ids
    LOOP
        CALL wodzone.delete_participant(participant_id);
    END LOOP;
  DELETE FROM wodzone.compet_event_modes WHERE id_competition = idCompetition;
  DELETE FROM wodzone.compet_tags WHERE id_competition = idCompetition;
  DELETE FROM wodzone.organisateurs WHERE id_competition = idCompetition;
  DELETE FROM wodzone.divisions WHERE id_competition = idCompetition;
  DELETE FROM wodzone.competitions WHERE id_competition = idCompetition;
END; $$



CREATE OR REPLACE PROCEDURE delete_participant(idParticipant integer)
LANGUAGE plpgsql
AS $$
DECLARE score_ids INTEGER[];
BEGIN
  SELECT ARRAY(SELECT id_score FROM wodzone.scores WHERE id_participant = idParticipant) INTO score_ids;
  delete from wodzone.score_details WHERE id_score = ANY(score_ids);
  delete from wodzone.scores where id_participant = idParticipant;
  delete from wodzone.athletes where id_participant =idParticipant;
  delete from wodzone.participants where id_participant =idParticipant;
END; $$

CALL wodzone.delete_competition(21)


