CREATE OR REPLACE PROCEDURE delete_wod(idWod integer)
LANGUAGE plpgsql
AS $$
DECLARE score_ids INTEGER[];
BEGIN
  SELECT ARRAY(SELECT id_score FROM wodzone.scores WHERE id_wod = idWod) INTO score_ids;
  DELETE FROM wodzone.score_details WHERE id_score = ANY(score_ids);

  DELETE FROM wodzone.scores WHERE id_wod = idWod;
  DELETE FROM wodzone.wod_score_details WHERE id_wod = idWod;
  DELETE FROM wodzone.wod_details WHERE id_wod = idWod;
 	DELETE FROM wodzone.wods WHERE id_wod = idWod;
END; $$


CREATE OR REPLACE PROCEDURE delete_PlanningWod(idPlanningWod integer)
LANGUAGE plpgsql
AS $$
DECLARE heat_ids INTEGER[];
BEGIN
  SELECT ARRAY(SELECT id_heat FROM wodzone.heats WHERE id_planning_wod = idPlanningWod) INTO heat_ids;
  DELETE FROM wodzone.lines WHERE id_heat = ANY(heat_ids);

  DELETE FROM wodzone.heats WHERE id_planning_wod = idPlanningWod;
  DELETE FROM wodzone.planning_wods WHERE id_planning_wod = idPlanningWod;
END; $$


CREATE OR REPLACE PROCEDURE delete_floor(idFloor integer)
LANGUAGE plpgsql
AS $$
DECLARE planning_wod_ids INTEGER[];
DECLARE heat_ids INTEGER[];
BEGIN
  SELECT ARRAY(SELECT id_planning_wod FROM wodzone.planning_wods WHERE id_floor = idFloor) INTO planning_wod_ids;
  SELECT ARRAY(SELECT id_heat FROM wodzone.heats WHERE id_planning_wod = ANY(planning_wod_ids)) INTO heat_ids;
  DELETE FROM wodzone.lines WHERE id_heat = ANY(heat_ids);

  DELETE FROM wodzone.heats WHERE id_planning_wod = ANY(planning_wod_ids);
  DELETE FROM wodzone.planning_wods WHERE id_planning_wod = ANY(planning_wod_ids);
  DELETE FROM wodzone.floors WHERE id_floor = idFloor;
END; $$


CREATE OR REPLACE PROCEDURE delete_participant(idParticipant integer)
LANGUAGE plpgsql
AS $$
DECLARE score_ids INTEGER[];
BEGIN
  SELECT ARRAY(SELECT id_score FROM wodzone.scores WHERE id_participant = idParticipant) INTO score_ids;
  delete from wodzone.score_details WHERE id_heat = ANY(score_ids);
  delete from wodzone.scores where id_participant = idParticipant;
  delete from wodzone.athletes where id_participant =idParticipant;
  delete from wodzone.participants where id_participant =idParticipant;
END; $$



